551→#[cfg(test)]
552→mod proptests {
553→    use super::*;
554→    use crate::test_arbitraries::arb_branch_decision;
555→    use proptest::prelude::*;
556→
557→    fn arb_severity() -> impl Strategy<Value = Severity> {
558→        prop_oneof![
559→            Just(Severity::RarePath),
560→            Just(Severity::HandledError),
561→            Just(Severity::UnhandledError),
562→            Just(Severity::Crash),
563→        ]
564→    }
