 93→    /// Load a behavior map for the given function ID, if one exists.
 94→    ///
 95→    /// Returns `Ok(None)` on cache miss, protocol version mismatch,
 96→    /// or deserialization failure (gracefully handles old cache format).
 97→    pub fn load(&self, function_id: &str) -> Result<Option<BehaviorMap>, CacheError> {
 98→        let path = self.path_for(function_id);
 99→        match fs::read_to_string(&path) {
100→            Ok(contents) => {
101→                let entry: BehaviorMapCacheEntry = match serde_json::from_str(&contents) {
102→                    Ok(e) => e,
103→                    // Old bare-JSON format or corrupt entry → cache miss
104→                    Err(_) => return Ok(None),
105→                };
106→                if entry.protocol_version != PROTOCOL_VERSION {
107→                    return Ok(None);
108→                }
109→                Ok(Some(entry.behavior_map))
110→            }
111→            Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(None),
112→            Err(e) => Err(CacheError::Io(e)),
113→        }
114→    }
