                exec_timeout,
                build_timeout,
                parallelism,
                timeout_per_fn,
                timeout_explore,
                output.as_deref(),
                &format,
                progress,
                emit_tests.as_deref(),
                dry_run,
                resume.as_deref(),
                mock_config.as_deref(),
                core_sample.as_deref(),
                seed,
                batch.as_deref(),
                stratum.as_deref(),
                log_level,
                memory_limit,
                cli.project_dir.as_deref(),
                use_color,
                &seeds_dir,
                no_seeds,
