                log_level,
                cli.project_dir.as_deref(),
                cache_dir.as_deref(),
                no_cache,
            )
            .await
            {
                Ok(all_fresh) => {
                    if all_fresh {
                        return ExitCode::SUCCESS;
                    }
                    return ExitCode::FAILURE;
                }
                Err(e) => Err(e),
            }
        }
        CliCommand::Revalidate {
            source,
            cache_dir,
            request_timeout,
            exec_timeout,
            build_timeout,
            memory_limit,
            format,
        } => {
            match run_revalidate(
