        /// Maximum generations for the genetic algorithm (default: 100).
        #[arg(long)]
        genetic_generations: Option<u32>,

        /// Timeout in seconds for the genetic algorithm (default: 300).
        #[arg(long)]
        genetic_timeout: Option<u32>,

