                max_iterations,
                timeout,
                timeout_explore,
                scope.as_deref(),
                analyze_only,
                show_clusters,
                cache_dir.as_deref(),
                no_cache,
                request_timeout,
                exec_timeout,
                build_timeout,
                inputs.as_deref(),
                config_path.as_deref(),
                output.as_deref(),
                log_level,
                cli.perf,
                &colors,
                spec || spec_json || spec_yaml || output.is_some() || invariants,
                spec_json || output.is_some(),
                spec_yaml,
                invariants || spec_yaml,
                concolic,
                solver_timeout,
                memory_limit,
                clean,
                dry_run,
                cli.project_dir.as_deref(),
                &loop_buckets,
                use_color,
                &seeds_dir,
                no_seeds,
            )
            .await
        }
        CliCommand::Scan {
